package ru.memearena;
import org.junit.jupiter.api.Test; import org.springframework.beans.factory.annotation.Autowired; import org.springframework.boot.test.autoconfigure.web.servlet.AutoConfigureMockMvc; import org.springframework.boot.test.context.SpringBootTest; import org.springframework.http.MediaType; import org.springframework.mock.web.MockMultipartFile; import org.springframework.test.context.*; import org.springframework.test.web.servlet.MockMvc; import org.testcontainers.containers.PostgreSQLContainer; import org.testcontainers.junit.jupiter.*; import java.util.regex.Pattern; import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.*; import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.*;
@Testcontainers @SpringBootTest @AutoConfigureMockMvc @ActiveProfiles({"test","local"}) class MediaIntegrationTests { @Container static final PostgreSQLContainer<?> POSTGRES=new PostgreSQLContainer<>("postgres:17-alpine"); @DynamicPropertySource static void db(DynamicPropertyRegistry r){r.add("spring.datasource.url",POSTGRES::getJdbcUrl);r.add("spring.datasource.username",POSTGRES::getUsername);r.add("spring.datasource.password",POSTGRES::getPassword);} @Autowired MockMvc mvc; @Test void uploadContentMemeModerateFlow() throws Exception {String u=mvc.perform(post("/api/v1/users/guest").contentType(MediaType.APPLICATION_JSON).content("{\"nickname\":\"MediaUser\"}")).andExpect(status().isCreated()).andReturn().getResponse().getContentAsString(); String uid=exPath(u,"user","id"); String token=ex(u,"accessToken"); var file=new MockMultipartFile("file","a.png","image/png",new byte[]{(byte)0x89,0x50,0x4e,0x47,0x0d,0x0a,0x1a,0x0a,1}); String up=mvc.perform(multipart("/api/v1/media/images").file(file).header("Authorization","Bearer "+token).param("userId",uid)).andExpect(status().isCreated()).andExpect(jsonPath("$.contentUrl").exists()).andReturn().getResponse().getContentAsString(); String mid=ex(up,"id"); var res=mvc.perform(get("/api/v1/media/"+mid+"/content")).andExpect(status().isOk()).andExpect(header().string("Content-Type","image/png")).andExpect(header().exists("ETag")).andReturn().getResponse(); mvc.perform(get("/api/v1/media/"+mid+"/content").header("If-None-Match",res.getHeader("ETag"))).andExpect(status().isNotModified()); String meme=mvc.perform(post("/api/v1/memes").header("Authorization","Bearer "+token).contentType(MediaType.APPLICATION_JSON).content("{\"uploaderId\":\""+uid+"\",\"title\":\"Uploaded\",\"mediaAssetId\":\""+mid+"\"}")) .andExpect(status().isCreated()).andExpect(jsonPath("$.moderationStatus").value("PENDING")).andExpect(jsonPath("$.contentUrl").value("/api/v1/media/"+mid+"/content")).andReturn().getResponse().getContentAsString(); String memeId=ex(meme,"id"); mvc.perform(get("/api/v1/local/moderation/memes")).andExpect(status().isOk()).andExpect(jsonPath("$.items[0].moderationStatus").value("PENDING")); mvc.perform(post("/api/v1/local/moderation/memes/"+memeId+"/approve")).andExpect(status().isOk()).andExpect(jsonPath("$.moderationStatus").value("APPROVED")); }
@Test void mediaErrors() throws Exception {String u=mvc.perform(post("/api/v1/users/guest").contentType(MediaType.APPLICATION_JSON).content("{\"nickname\":\"ErrUser\"}")).andReturn().getResponse().getContentAsString(); String uid=exPath(u,"user","id"); String token=ex(u,"accessToken"); mvc.perform(multipart("/api/v1/media/images").file(new MockMultipartFile("file","e.png","image/png",new byte[]{})).header("Authorization","Bearer "+token).param("userId",uid)).andExpect(status().isBadRequest()).andExpect(jsonPath("$.code").value("EMPTY_FILE")); mvc.perform(multipart("/api/v1/media/images").file(new MockMultipartFile("file","a.txt","text/plain",new byte[]{1})).header("Authorization","Bearer "+token).param("userId",uid)).andExpect(status().isUnsupportedMediaType()); mvc.perform(post("/api/v1/memes").header("Authorization","Bearer "+token).contentType(MediaType.APPLICATION_JSON).content("{\"uploaderId\":\""+uid+"\",\"title\":\"Bad\",\"imageUrl\":\"https://e/a.png\",\"mediaAssetId\":\"00000000-0000-0000-0000-000000000001\"}")) .andExpect(status().isBadRequest()).andExpect(jsonPath("$.code").value("INVALID_MEDIA_SOURCE")); }
static String exPath(String json,String obj,String field){var m=Pattern.compile("\\\""+obj+"\\\":\\{[^}]*\\\""+field+"\\\":\\\"([^\\\"]+)\\\"").matcher(json); if(!m.find()) throw new IllegalStateException(json); return m.group(1);} static String ex(String j,String f){var m=Pattern.compile("\\\""+f+"\\\":\\\"([^\\\"]+)\\\"").matcher(j); if(!m.find()) throw new IllegalStateException(j); return m.group(1);} }
